INSERT INTO auth.opcion_menu (modulo_id, codigo, nombre, ruta_frontend, path_url, opcion_padre_id, orden, flag_estado)
SELECT p.modulo_id, d.codigo, d.nombre, d.ruta, d.path_url, p.id, d.orden, '1'
FROM d JOIN auth.opcion_menu p ON p.codigo = d.parent_codigo
ON CONFLICT (codigo) DO UPDATE SET
    modulo_id = EXCLUDED.modulo_id, nombre = EXCLUDED.nombre,
    ruta_frontend = EXCLUDED.ruta_frontend, path_url = EXCLUDED.path_url,
    opcion_padre_id = EXCLUDED.opcion_padre_id,
    orden = EXCLUDED.orden, flag_estado = '1';

